//#region src/util/throttle.ts
/**
* Throttle the given function to run at most every `period` milliseconds.
*/
function throttle(fn, time) {
	let pending = false;
	let timerId = null;
	let lastCallArgs;
	const later = () => {
		timerId = null;
		if (pending) {
			fn(...lastCallArgs);
			timerId = setTimeout(later, time);
			pending = false;
		}
	};
	return (...args) => {
		pending = true;
		lastCallArgs = args;
		if (!timerId) later();
		return timerId;
	};
}
